+/// A streaming body for gRPC messages.
+pub trait Streaming: Send {
+    /// The message type.
+    type Message;
+
+    /// Poll for the next message.
+    fn poll_next(
+        self: Pin<&mut Self>,
+        cx: &mut Context<'_>,
+    ) -> Poll<Option<Result<Self::Message, Status>>>;
+}
