+impl<T> Default for StreamingRequest<T> {
+    fn default() -> Self {
+        Self::new()
+    }
+}
+
+impl<T: Send> Streaming for StreamingRequest<T> {
+    type Message = T;
+
+    fn poll_next(
+        self: Pin<&mut Self>,
+        _cx: &mut Context<'_>,
+    ) -> Poll<Option<Result<Self::Message, Status>>> {
